90	  let count = 0;
91	  if (filters.fileType.length > 0) count++;
92	  if (filters.status.length > 0) count++;
93	  if (filters.workflowStatus.length > 0) count++;
94	  if (filters.isLicensed !== null) count++;
95	  if (filters.licensorId) count++;
96	  if (filters.propertyId) count++;
97	  if (filters.assetType.length > 0) count++;
98	  if (filters.artSource.length > 0) count++;
99	  if (filters.tagFilter) count++;
100	  if (filters.fileStatus.length > 0) count++;
101	  if (filters.productCategory.length > 0) count++;
102	  if (filters.stage.length > 0) count++;
103	  if (filters.customer) count++;
104	  if (filters.program) count++;
105	  return count;
106	}
